import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";
import background from "../assets/background.png";
import axios from "axios";

const Form = () => {
  const [email, setEmail] = useState("");
  const [image, setImage] = useState(null);
  const [option, setOption] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      formData.append("file", image);
      const response = await axios.post("http://localhost:8000/predict/", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      navigate("/result", {
        state: {
          gem_prediction: response.data.gem_prediction,
          shape_prediction: response.data.shape_prediction,
          image: formData.get("file"),
        },
      });
    } catch (error) {
      console.error("Error submitting form:", error);
    }
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    setImageUrl(URL.createObjectURL(file));
  };

  return (
    <>
      <Topnav />

      <div
        className="bg-cover bg-center py-14"
        style={{ backgroundImage: `url(${background})` }}
      >
        <p className="text-4xl font-bold max-w-5xl mx-auto text-center text-gray-900 mb-8">
          Gem Analysis
        </p>

        <form onSubmit={handleSubmit} className="max-w-3xl mx-auto bg-white p-8 rounded-xl shadow-lg">
          {/* Email Input */}
          <div className="mb-6">
            <label htmlFor="email" className="block mb-2 font-semibold text-gray-700">
              Email Address
            </label>
            <p className="text-sm text-gray-500 mb-2">
              Provide your email if you want to receive your gem analysis report.
            </p>
            <input
              type="email"
              id="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:outline-none"
              placeholder="Enter your email"
            />
          </div>

          {/* Image Upload */}
          <div className="mb-6">
            <label htmlFor="image" className="block mb-2 font-semibold text-gray-700">
              Upload your image
            </label>
            <label
              htmlFor="image"
              className="flex flex-col items-center justify-center w-full h-64 border-2 border-dashed border-gray-300 rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100 relative"
            >
              {imageUrl ? (
                <img src={imageUrl} alt="Uploaded" className="max-w-full max-h-full rounded-lg" />
              ) : (
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <svg
                    className="w-8 h-8 mb-4 text-gray-400"
                    aria-hidden="true"
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 20 16"
                  >
                    <path
                      stroke="currentColor"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth="2"
                      d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"
                    />
                  </svg>
                  <p className="mb-2 text-sm text-gray-500 font-semibold">Click to upload or drag and drop</p>
                  <p className="text-xs text-gray-400">SVG, PNG, JPG or GIF (MAX. 800x400px)</p>
                </div>
              )}
              <input
                type="file"
                id="image"
                onChange={handleImageChange}
                accept="image/*"
                className="hidden"
              />
            </label>
          </div>

          {/* Option Radio */}
          <div className="mb-6">
            <label className="block mb-2 font-semibold text-gray-700">
              Do you want to identify the cut of the Gem?
            </label>
            <div className="flex gap-6">
              <label className="flex items-center gap-2">
                <input
                  type="radio"
                  value="yes"
                  checked={option === "yes"}
                  onChange={() => setOption("yes")}
                  className="accent-blue-600"
                />
                Yes
              </label>
              <label className="flex items-center gap-2">
                <input
                  type="radio"
                  value="no"
                  checked={option === "no"}
                  onChange={() => setOption("no")}
                  className="accent-blue-600"
                />
                No
              </label>
            </div>
          </div>

          {/* Submit Button */}
          <div className="flex justify-end">
            <button
              type="submit"
              className="px-6 py-2 text-white font-semibold rounded-full bg-blue-700 hover:bg-blue-800 transition duration-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              Continue
            </button>
          </div>
        </form>
      </div>

      <Footer />
    </>
  );
};

export default Form;
